import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.BYlK8ftn.js";const p=JSON.parse('{"title":"Generated 3D assets","description":"","frontmatter":{},"headers":[],"relativePath":"guide/assets.md","filePath":"guide/assets.md","lastUpdated":1781997150000}'),s={name:"guide/assets.md"};function d(i,e,n,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="generated-3d-assets" tabindex="-1">Generated 3D assets <a class="header-anchor" href="#generated-3d-assets" aria-label="Permalink to &quot;Generated 3D assets&quot;">​</a></h1><p>Catalog of the game&#39;s generated 3D models. All models are produced <strong>per concrete character/prop ticket only</strong> (never speculatively — board directive <a href="/korovany/plan/game-plan">FLO-270</a>) via the <code>tools/meshy-3d</code> pipeline, in <strong>low-poly visual language v1.2</strong> (≤ 3000 tris/object, flat-shaded palette materials).</p><p>Files live under <code>public/models/*.glb</code> and stream into the scene through the <a href="./asset-streaming">asset-streaming</a> registry. Binaries are stored in <strong>Git LFS</strong> (see <code>.gitattributes</code>). Generation is reproducible from the recorded Meshy task id (<code>python tools/meshy-3d/meshy.py status &lt;task_id&gt; --kind text-to-3d</code>).</p><h2 id="licensing" tabindex="-1">Licensing <a class="header-anchor" href="#licensing" aria-label="Permalink to &quot;Licensing&quot;">​</a></h2><p>Generated assets are cleared for FlopBut&#39;s intended (incl. commercial) use under the Meshy paid-plan terms, which grant full commercial ownership of generated output. No infringing reference inputs are used, and these assets are kept out of any Community/showcase page.</p><h2 id="characters-props" tabindex="-1">Characters &amp; props <a class="header-anchor" href="#characters-props" aria-label="Permalink to &quot;Characters &amp; props&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>File</th><th>Tris</th><th>Size</th><th>Rig</th><th>Meshy task id</th></tr></thead><tbody><tr><td>Player hero (elf)</td><td><code>public/models/korovany_hero_player-default.glb</code></td><td>2894</td><td>—</td><td>static (no skeleton)</td><td>—</td></tr><tr><td>Conifer tree</td><td><code>public/models/forest-tree.glb</code></td><td>1357</td><td>—</td><td>static</td><td>—</td></tr><tr><td>Wooden hut</td><td><code>public/models/wooden-hut.glb</code></td><td>1893</td><td>—</td><td>static</td><td>—</td></tr><tr><td>Chest</td><td><code>public/models/chest.glb</code></td><td>—</td><td>—</td><td>static</td><td>—</td></tr><tr><td><strong>Empire soldier (enemy)</strong></td><td><code>public/models/empire-soldier.glb</code></td><td><strong>2794</strong></td><td>130 KiB</td><td>static (no skeleton)</td><td><code>019ee601-93f0-7988-86f8-e35ce1067881</code></td></tr><tr><td><strong>Roadside shrine (Salt Road)</strong></td><td><code>public/models/roadside-shrine.glb</code></td><td><strong>1984</strong></td><td>394 KiB</td><td>static</td><td><code>019ee73a-c8a6-73bd-a2ec-e21137a6dba2</code> (preview) / <code>019ee747-ae35-786a-a8c7-490e65d0cddd</code> (retexture)</td></tr></tbody></table><h3 id="empire-soldier-enemy-—-phase-2" tabindex="-1">Empire soldier (enemy) — Phase 2 <a class="header-anchor" href="#empire-soldier-enemy-—-phase-2" aria-label="Permalink to &quot;Empire soldier (enemy) — Phase 2&quot;">​</a></h3><p>Napoleonic-era Empire infantryman: bicorne hat, greatcoat, boots, musket held across the body. Generated for <a href="/korovany/plan/game-plan">FLO-311</a> (feeds the enemy-NPC ticket E2.3).</p><ul><li><strong>Budget:</strong> 2794 tris ≤ 3000 (v1.2). Bounding box ≈ 0.97 × 1.90 × 0.84 units (humanoid, ~1.9 tall). Preview-only — no PBR textures (refine is skipped for v1.2; PBR refine drifts the faceted low-poly look into a semi-realistic band).</li><li><strong>Provenance:</strong> Meshy text-to-3D preview, <code>--art-style realistic --target-polycount 3000</code>. Prompt: <em>&quot;low-poly stylized empire soldier enemy, humanoid game character standing in a neutral A-pose, military uniform with peaked helmet and boots, holding a musket rifle, faceted flat-shaded surfaces, muted grey-green palette, full body, single character&quot;</em>. Meshy emitted 3105 tris; welded + decimated to 2794 with <code>gltf-transform</code> (<code>weld</code> → <code>simplify --ratio 0.9 --error 0.01</code>) to fit the budget — silhouette/bbox unchanged. 20 Meshy credits (preview only).</li><li><strong>Rig:</strong> ships <strong>unrigged (static mesh, no skeleton/animation clips)</strong> — this matches the player hero GLB, which is also a static mesh, so the same loader / controller code handles it without special-casing. There is <strong>no hero rig to reuse</strong> (hero has 0 skeletons). E2.3 must therefore drive idle/walk/attack/death either procedurally (transform-level) or by adding a skeletal rig in a separate pass (Meshy auto-rigging is available but was out of scope for this asset-only ticket). Flag rig needs to Pygmalion if a skeletal pass is wanted.</li><li><strong>Verification:</strong> loads headless via <code>node tools/meshy-3d/smoke_load_glb.mjs public/models/empire-soldier.glb</code> → 2 meshes, 2794 tris, no errors.</li></ul><h3 id="roadside-shrine-salt-road-—-phase-3-5-mpg" tabindex="-1">Roadside shrine (Salt Road) — Phase 3.5 (MPG) <a class="header-anchor" href="#roadside-shrine-salt-road-—-phase-3-5-mpg" aria-label="Permalink to &quot;Roadside shrine (Salt Road) — Phase 3.5 (MPG)&quot;">​</a></h3><p>Humble rural Salt Road landmark (<a href="/korovany/plan/world-specs">world-specs</a> §1), replacing the placeholder colored box in <code>src/scenes/humanLandsScene.ts</code>. Small weathered stone structure with an arched niche, aged-wood back, and a low offering ledge — a readable, distinct silhouette. Generated for <a href="/korovany/plan/game-plan">FLO-375</a>.</p><ul><li><strong>Budget:</strong> 1984 tris ≤ 2000 (within ticket budget), <strong>394 KiB</strong> web payload. Bounding box ≈ 1.52 × 2.00 × 1.15 units (real-world scale, ~2 m tall).</li><li><strong>Textured</strong> (board mandate — never grey): single 1024² base-color map, flat/unlit albedo (worn pale stone with moss accents + aged grey-brown wood).</li><li><strong>Provenance:</strong> Meshy text-to-3D <strong>preview</strong> (<code>019ee73a-…</code>, geometry only, 1985 tris, 20 cr) → <strong>retexture</strong> (<code>019ee747-…</code>, geometry-preserving UV-unwrap <ul><li>paint, 10 cr) → <code>resize_glb_textures.py --max 1024 --quality 85</code> (4.3 MiB → 394 KiB, mesh bytes untouched). Retexture over PBR refine keeps the faceted low-poly silhouette (<a href="#">meshy PBR drift</a> — see <code>API-FITNESS.md</code>). Prompt: <em>&quot;low-poly stylized roadside shrine, small weathered stone structure with an arched niche, simple offering ledge, worn pale stone and aged wood, faceted flat-shaded, humble rural fantasy aesthetic, readable silhouette&quot;</em>; retexture style prompt: <em>&quot;worn pale weathered stone shrine with aged grey-brown wood, humble rural fantasy, flat low-poly muted earthy palette, faceted unlit albedo&quot;</em>.</li></ul></li><li><strong>Rig:</strong> static prop — no skeleton.</li><li><strong>Verification:</strong> loads headless via <code>node tools/meshy-3d/smoke_load_glb.mjs public/models/roadside-shrine.glb</code> → 2 meshes, 1984 tris, 1 embedded texture, no errors.</li><li><strong>Handoff:</strong> wiring this GLB into the scene (replacing the procedural box in <code>humanLandsScene.ts</code>) is engineering&#39;s job — handed to Daedalus/CTO.</li></ul>',13)])])}const m=t(s,[["render",d]]);export{p as __pageData,m as default};
